var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"에헤~ 여긴 조금 특이한 장소네~?","JPN":"へえ～、ここってちょっと変わってるね～？","ENG":"Oh? This place is a little special, huh?","TWN":"嘿嘿～這是有點特別的場所呢～？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그래서어? 무슨 일이야? 이런 시간에… 이런 장소에서 이렇게 단 둘이 만나자는 건…….","JPN":"それでぇ？　何の用？　こんな時間に、こんな場所で……二人きりで会おうだなんて……","ENG":"So? What's the deal? Calling me out here... at this hour... just the two of us...","TWN":"所以呢？怎麼了？在這種時間…在這種地方，要跟我單獨見面……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그래, 드디어 질-펀하게 붙어볼 생각이구나아?","JPN":"そっか、やっとアタシとガチでやる気になったんだ～？","ENG":"Oh, I get it. You finally wanna have a real brawl, don't you?","TWN":"原來，終於想要好～好跟我打一場了嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"아하하핫……!","JPN":"あはははっ……！","ENG":"Ahahaha...!","TWN":"哈哈哈哈……！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그럼, 어디 놀아 볼까~?","JPN":"じゃあ、存分に楽しんでみよっかな～？","ENG":"Then, shall we play a little?","TWN":"那，就來好好玩一下吧～？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"뭐야, 시시하네? 왜 이렇게 이리 약해 빠졌어~?","JPN":"なんだ、つまんな～い。なんでそんなに弱っちいの～？","ENG":"Huh? That was way too easy. Why're you so weak?","TWN":"咦？也太無聊了吧？你怎麼會這麼弱～？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그런데… 이상하네에?","JPN":"でも……おかしいなぁ？","ENG":"But... that's strange.","TWN":"但是…有點奇怪欸？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"네가 사장이면… 단장처럼 이 회사에서 가장 강하다는 뜻 아니야……?","JPN":"君が社長ってことは……団長みたいに、この会社で一番強いってことじゃない……？","ENG":"If you're the boss, doesn't that mean you're the strongest one here like the Captain...?","TWN":"如果你是老闆的話…那就像團長一樣，是這公司最強的人不是嗎……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"히힛, 귀여워라. 이렇게 손도 발도 꼼짝 못 하니까, 꼭 아기 같잖아?","JPN":"ひひっ、かわいい。手も足も出なくなって、赤ちゃんみたい。","ENG":"Teehee, how cute. You're all tied up and helpless, just like a baby.","TWN":"嘻嘻，真可愛。這樣手腳都動不了的樣子，就像個孩子一樣呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"우쭈주~ 이제 어떻게 해줄까? 어디를 어떻게 꺾으면, 넌 어떤 비명을 지르려나아?","JPN":"よちよち～、次はどうしようか？　どこをどんな風に捻ると、どういう悲鳴が出るのかなぁ？","ENG":"Aww, what should I do with you now? How should I twist you, and what kind of scream will you make?","TWN":"乖乖～現在要怎麼做呢？要折彎什麼地方，你才會發出尖叫呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"이렇게? 이렇게에?","JPN":"こう？　それともこう～？","ENG":"Like this? Or like this?","TWN":"這樣？還是這樣？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"……응?","JPN":"……うん？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"오해라고~? 무슨 오해애?","JPN":"誤解だって～？　何がぁ？","ENG":"A misunderstanding? What misunderstanding?","TWN":"誤會～？什麼誤會？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"나랑 싸우려고 부른 게 아니라고?","JPN":"アタシと戦うために呼んだわけじゃない？","ENG":"You didn't call me here to fight?","TWN":"你找我來不是想跟我打架嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그럼, 뭐야?","JPN":"じゃあ、なに？","ENG":"Then what was it for?","TWN":"不然呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"종신… 계약서……?","JPN":"終身……契約書……？","ENG":"A lifetime... contract...?","TWN":"終身…契約書……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"저기이, 종신이 무슨 뜻인데? 이렇게 어려운 건 잘 모른다구우~?","JPN":"ねぇ、終身ってどういうこと？　アタシ難しいことはわかんないよ～？","ENG":"Hey, what does \\"lifetime\\" even mean? Complicated stuff like that goes right over my head.","TWN":"不過，終身是什麼意思？我不太懂這麼難的事情啊～？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"아아? 내가 곁에 있어 줬으면 좋겠어? 지켜줬으면 좋겠어?","JPN":"あぁ～、アタシに傍にいてほしい？　守ってほしいって？","ENG":"Oh? You want me to stay by your side? To protect you?","TWN":"啊啊？希望我待在你身邊？希望我守護著你？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그것도 평생?","JPN":"しかも、一生？","ENG":"For life?","TWN":"而且還是一輩子？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그건, 너만의 기사가 되어달라는 뜻일까나?","JPN":"それって、君だけの騎士になってほしいってこと？","ENG":"So, you want me to be your knight, is that it?","TWN":"那就是，要我當你專屬的騎士嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"기사 서약 같은 건, 단장님한테 말만 들었지 해본적은 없는데에……?","JPN":"騎士の誓約とか、団長に聞いたことはあるけど、実際やったことはないんだよねぇ……","ENG":"I've only ever heard the Captain talk about knightly vows, never made one myself though...","TWN":"騎士誓約這種事我只有聽團長說過，但沒有試過欸……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"있지, 있지이? 정말, 이런 나로도 괜찮겠어?","JPN":"ねぇ、ねえ～、本当に、こんなアタシでいいの？","ENG":"Hey, hey. Are you sure you're okay with someone like me?","TWN":"不過啊？像我這樣的人真的沒關係嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"응, 나도 좋아! 네 기사가 되어줄게!","JPN":"うん、いいよ！　君の騎士になってあげる！","ENG":"Mm, okay. I'll be your knight!","TWN":"嗯，那好！我要當你的騎士！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"왜냐하면 너는 약하지만, 너랑 있으면 왠지 가슴이 두근두근해서 참을 수가 없거든.","JPN":"だって君は弱いけど、君といると何だか心臓がバクバクしてたまらないんだもん。","ENG":"Because you're weak, but whenever I'm with you, my heart starts pounding and I just can't hold it back.","TWN":"因為，你雖然很弱，但總覺得跟你在一起，我的心就會忍不住撲通撲通地跳。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"이런 설레는 기분, 제법 나쁘지 않은 걸~?","JPN":"こんなドキドキ感、嫌いじゃないし～？","ENG":"This fluttery feeling... it's not bad at all.","TWN":"這種心動的感覺，還不算太差～？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"네가 사장이면… 어쨌든 중요한 사람이지? 널 노리는 강한 녀석들이랑 진탕 싸울 수 있겠네?","JPN":"君は社長だから……とにかく、偉い人だよね？　君を狙ってる強いやつらと、たっぷり戦えるよね？","ENG":"You're the boss... so you're important, right? Then I'll get to fight all the strong ones who come after you!","TWN":"如果你是老闆…反正就是很重要的人吧？這樣我就能跟盯上你的強者痛快地打上一場了吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"복잡한 건, 잘 모르겠지만…….","JPN":"難しいことは、よくわかんないけど……","ENG":"I don't really get the complicated stuff...","TWN":"雖然複雜的事我不是很懂……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"뭐, 서로의 목숨 걸고 싸울 수만 있다면, 그런 건 아무래도 좋아~","JPN":"まあ、命かけて殺し合えるなら、そんなのどうでもいいや～","ENG":"But as long as we can risk our lives together in battle, that's all that matters!","TWN":"嗯，但如果是賭上彼此的性命戰鬥的話，不管怎樣都好～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"자, 우리 기사 서약을 맺자. 사장.","JPN":"それじゃ、騎士の誓約を交わそう、社長。","ENG":"Come on, let's seal our knight's vow, Boss.","TWN":"好，我們就來簽騎士誓約吧，老闆。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L7_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"단장님말로는 뭔가 입맞춤을 해야 한다고 했던 것 같긴 한데…….","JPN":"確か団長が、口づけしなきゃいけないとか何とか言ってたような……","ENG":"I remember the Captain saying it involves a kiss or something...","TWN":"團長好像說過必須在嘴上蓋章之類的話……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"흐음, 어디다 해야 해? 입맞춤?","JPN":"うーん。口づけ、どこにすればいい？","ENG":"Hmm, but where do I kiss you?","TWN":"嗯，要蓋在哪裡？嘴巴嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};